import math
import random

def calculate_square_root(value: float) -> float:
    """Calculate the square root of a given value."""
    return math.sqrt(value)

def generate_random_number(start: int, end: int) -> int:
    """Generate a random number between start and end."""
    return random.randint(start, end)

def main() -> None:
    value = 16.0
    print("Square root of", value, "is", calculate_square_root(value))

    start = 1
    end = 10
    print("Random number between", start, "and", end, "is", generate_random_number(start, end))

if __name__ == "__main__":
    main()
